<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Helix – Distributed Tracing for Streaming Data Pipelines</title>
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<style>
  :root {
    --bg-dark: #0a0c12;
    --bg-darker: #050607;
    --accent: #0ff;               /* cyan accent */
    --text-primary: #e0e2e6;
    --text-secondary: #adb5bf;
    --font: system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, "Helvetica Neue", Arial, sans-serif;
  }
  * { margin:0; padding:0; box-sizing:border-box; }
  body { font-family: var(--font); background:#0a0c12; color:var(--text-primary); }
  /* ---- Sticky Nav ---- */
  .nav-bar {
    position: sticky; top:0; z-index:1000;
    display:flex; align-items:center; justify-content:space-between;
    padding:0.5rem 2rem; background:var(--bg-dark);
  }
  .nav-bar a, .nav-bar .logo, .nav-bar .cta {
    color:var(--text-primary); text-decoration:none;
    transition:color 0.2s ease;
  }
  .nav-bar a:hover, .nav-bar .cta:hover { color:var(--accent); }
  .logo { font-weight:600; font-size:1.2rem; }
  .nav-links { display:flex; gap:1.5rem; }
  .cta { background:var(--accent); color:var(--bg-dark);
         padding:0.4rem 0.9rem; border-radius:0.3rem; }
  /* ---- Hero ---- */
  .hero {
    display:flex; flex-direction:row; align-items:center;
    padding:4rem 2rem;
    background:linear-gradient(135deg, var(--bg-dark) 30%, var(--bg-darker) 70%);
  }
  .hero .content {
    max-width:860px; width:100%;
  }
  .hero h1 { margin-bottom:0.4rem; font-size:2.6rem; }
  .hero p { margin-bottom:1.2rem; font-size:1.25rem; line-height:1.5; color:var(--text-secondary); }
  .hero .btn-primary, .hero .btn-secondary {
    display:inline-block; padding:0.7rem 1.4rem; border-radius:0.4rem;
    font-size:1rem; margin-right:0.8rem; transition:transform 0.15s ease;
  }
  .hero .btn-primary { background:var(--accent); color:var(--bg-dark); }
  .hero .btn-secondary { background:transparent; border:2px solid var(--accent); color:var(--accent); }
  .hero .btn-primary:hover, .hero .btn-secondary:hover { transform:scale(1.03); }
  /* Terminal panel */
  .terminal {
    flex:0 0 42%; min-width:300px; width:45%; background:#111;
    border-left:4px solid var(--accent); color:#8fa4b8;
    padding:2rem; box-shadow:0 0 12px rgba(0,0,0,0.6);
    font-family: "Courier New", monospace; resize:none; overflow:hidden;
  }
  .terminal pre {
    margin:0; white-space-pre-wrap; font-size:0.95rem;
    animation:scrollTerminal 12s linear infinite;
  }
  @keyframes scrollTerminal {
    0%   { transform:translateY(0); }
    100% { transform:translateY(-200vh); }
  }
  /* ---- Feature Grid ---- */
  .features {
    display:grid; grid-template-columns:repeat(3,1fr);
    gap:2rem; padding:4rem 2rem;
    background:var(--bg-dark);
  }
  .feature {
    text-align:center; max-width:300px; margin:auto;
  }
  .feature svg { width:80px; height:80px; color:var(--accent); margin-bottom:1rem; }
  .feature h3 { margin-bottom:0.6rem; font-size:1.4rem; }
  .feature p { font-size:1rem; color:var(--text-secondary); }
  /* ---- Customer Logos ---- */
  .logos {
    display:flex; justify-content:center; gap:0.9rem;
    padding:2rem 0;
    background:var(--bg-darker);
  }
  .logo-badge { width:110px; height:30px; background:#161a23;
                border-radius:0.35rem; display:flex; align-items:center; justify-content:center;
                color:var(--text-secondary); font-size:0.85rem; }
  /* ---- Product Tour ---- */
  .tour {
    background:var(--bg-dark); padding:4rem 0;
    display:grid; grid-template-rows:repeat(4,auto); row-gap:2.5rem;
    text-align:center;
  }
  .tour .step {
    border:2px solid var(--accent); border-radius:0.6rem;
    padding:2.2rem; position:relative;
  }
  .tour .step::before {
    content:""; position:absolute; inset:0; border-radius:0.6rem;
    background:linear-gradient(120deg, transparent 40%, rgba(255,255,255,0.07) 60%);
    pointer-events:none;
  }
  .tour h4 { margin-bottom:0.7rem; font-size:1.3rem; }
  .tour p { font-size:1rem; color:var(--text-secondary); }
  .tour .badge {
    position:absolute; bottom:0.4rem; right:0.4rem;
    background:var(--accent); color:var(--bg-dark);
    border-radius:0.3rem; padding:0.2rem 0.6rem;
    font-size:0.75rem; text-transform:uppercase;
  }
  /* ---- Pricing Teaser ---- */
  .pricing {
    background:#111; padding:3rem 2rem; text-align:center;
  }
  .pricing a {
    display:inline-block; padding:0.6rem 1.2rem;
    background:var(--accent); color:var(--bg-dark);
    border-radius:0.4rem; text-decoration:none;
  }
  /* ---- Footer ---- */
  footer {
    background:var(--bg-darker); color:var(--text-secondary);
    padding:3rem 2rem; text-align:center;
  }
  footer nav {
    display:grid; grid-template-columns:repeat(4,1fr);
    gap:2rem; justify-content:center;
    margin-top:1.5rem;
  }
  footer nav a { color:var(--text-secondary); text-decoration:none; }
  footer .status-badge {
    background:var(--accent); color:var(--bg-dark);
    padding:0.3rem 0.7rem; border-radius:0.35rem;
    font-size:0.85rem; margin-top:1rem;
  }
  /* Micro‑interactions */
  .nav-bar, .hero .btn-primary, .hero .btn-secondary,
  .feature svg, .tour .step, .logo-badge {
    transition:transform 0.2s ease;
  }
  .nav-bar:hover, .feature:hover svg,
  .tour .step:hover, .logo-badge:hover {
    transform:scale(1.04);
  }
</style>
</head>
