});

/* ---------- Environment switcher ---------- */
const envBtn = document.getElementById('env-btn');
const envMenu = document.querySelector('#env-switch .menu');
envBtn.addEventListener('click', () => envMenu.classList.toggle('open'));
document.querySelectorAll('#env-switch button[data-env]').forEach(btn => {
  btn.addEventListener('click', () => {
    envBtn.textContent = btn.textContent;
    envMenu.classList.remove('open');
    // simple state indicator – you could dispatch a custom event here
  });
});

/* ---------- Date range apply (demo only) ---------- */
document.getElementById('apply-range').addEventListener('click', () => {
  console.info('Date range applied:', 
    document.getElementById('start-date').value,
    document.getElementById('end-date').value);
});

/* ---------- Sparkline demo – static values (already set in HTML) ---------- */
/* No runtime update needed for this demo. */

/* ---------- SVG line‑chart hover tooltip ---------- */
const svg = document.getElementById('chart');
const path = document.getElementById('line-path');
const tooltip = document.createElement('div');
tooltip.className = 'tooltip';
svg.appendChild(tooltip);

function getPointAtPercent(t) {
  const pathLen = path.getTotalLength();
  const pos = path.getPointAtLength(t * pathLen);
  return {x: pos.x, y: pos.y};
}

svg.addEventListener('mousemove', e => {
  const rect = svg.getBoundingClientRect();
  const x = e.clientX - rect.left; // client X relative to SVG
  const total = path.getTotalLength();
  const closest = path.getClosestPointTo(x, svg.clientHeight);
  // SVG2 API `getClosestPointTo` not universally supported – fallback to sampling
  if (!closest) {
    // simple fallback: sample every 5% along path
    let best = {dist: Infinity, t:0};
    for (let i=0;i<=20;i++){
      const pt = getPointAtPercent(i/20);
      const dx = pt.x - x;
      const dy = pt.y - e.clientY - rect.top;
      const d = dx*dx + dy*dy;
      if (d < best.dist){ best = {dist:d, t:i/20}; }
    }
    const pt = getPointAtPercent(best.t);
    tooltip.textContent = `${Math.round(pt.x/10)*10} h → ${Math.round(200 - pt.y)} ms`;
    tooltip.style.left = `${pt.x + 10}px`;
    tooltip.style.top  = `${pt.y - 30}px`;
    tooltip.classList.add('visible');
  } else {
    tooltip.textContent = `${Math.round(closest.x/10)*10} h → ${Math.round(200 - closest.y)} ms`;
    tooltip.style.left = `${closest.x + 10}px`;
    tooltip.style.top  = `${closest.y - 30}px`;
    tooltip.classList.add('visible');
  }
});

svg.addEventListener('mouseleave', () => tooltip.classList.remove('visible'));

/* ---------- Table sorting (simple client‑side) ---------- */
function sortTable(key) {
  const th = this;
  const table = document.getElementById('service-table');
  const tbody = table.tBodies[0];
  const rows = Array.from(tbody.querySelectorAll('tr'));

  // Determine column index
  const idxMap = {};
  const header = Array.from(table.querySelector('thead th').parentElement.children[0].children);
  header.forEach((h, i) => { idxMap[h.textContent.trim()] = i; });
  const colIdx = idxMap[key];

  // Toggle sort direction
  if (th.classList.contains('sort-asc')) {
    th.classList.remove('sort-asc');
    th.classList.add('sort-desc');
    rows.sort((a,b) => {
      const aVal = a.children[colIdx].textContent;
      const bVal = b.children[colIdx].textContent;
      // numeric for latency / error, lexicographic otherwise
      if (key === 'p99' || key === 'error') {
        return parseFloat(aVal) - parseFloat(bVal);
      }
      return aVal.localeCompare(bVal);
    });
  } else {
    th.classList.remove('sort-desc');
    th.classList.add('sort-asc');
    rows.sort((a,b) => {
      const aVal = a.children[colIdx].textContent;
      const bVal = b.children[colIdx].textContent;
      if (key === 'p99' || key === 'error') {
        return parseFloat(aVal) - parseFloat(bVal);
      }
      return aVal.localeCompare(bVal);
    });
  }

  // Re‑append rows
  rows.forEach(r => tbody.appendChild(r));
  // Clear any other column sort class
  Array.from(table.querySelectorAll('th')).forEach(t => {
    t.classList.remove('sort-asc','sort-desc');
  });
  th.classList.add(key === 'p99' || key === 'error' ? 'sort-asc' : 'sort-asc'); // default asc
}

// Attach click handler to all sortable headers
document.querySelectorAll('#service-table th[onclick]').forEach(th => {
  th.addEventListener('click', sortTable.bind(th, th.textContent.trim()));
});
</script>
</body>
</html>
