<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Fluid‑like Particle Swarm</title>
<style>
  body { margin:0; overflow:hidden; background:#0b0b0b; }
  canvas { display:block; }
</style>
</head>
<body>
<canvas id="c"></canvas>

<script>
(() => {
  'use strict';

  const canvas = document.getElementById('c');
  const ctx = canvas.getContext('2d');

  // ---------------------------------------------------
  // Helper: resize canvas respecting devicePixelRatio
  // ---------------------------------------------------
  function resize() {
    const dpr = window.devicePixelRatio || 1;
    const w = canvas.clientWidth  * dpr;
    const h = canvas.clientHeight * dpr;
    if (canvas.width !== w || canvas.height !== h) {
      canvas.width  = w;
      canvas.height = h;
      ctx.scale(dpr, dpr);
    }
  }
  window.addEventListener('resize', resize);
  resize();   // initial size

  // ---------------------------------------------------
  // Particle definition
  // ---------------------------------------------------
  class Particle {
    constructor(x, y) {
      this.x = x;
      this.y = y;
      // modest random speed (magnitude 0.5‑2)
      const speed = 0.5 + Math.random() * 1.5;
      const angle = Math.random() * Math.PI * 2;
      this.vx = Math.cos(angle) * speed;
      this.vy = Math.sin(angle) * speed;
      // each particle gets a slightly different hue (cool palette)
      this.hue = (150 + Math.random() * 30) % 360;   // 150‑180 ≈ cyan‑blue
    }

    // simple Euler integration + damping
    update(targetX, targetY, dt = 1/60) {
      // ----- attraction to mouse (or centre) -----
      const dx = targetX - this.x;
      const dy = targetY - this.y;
      const distSq = dx*dx + dy*dy + 0.0001;        // avoid div‑by‑0
      const attract = 0.02;                        // strength
      const force = attract * dt / Math.sqrt(distSq);
      this.vx += dx * force;
      this.vy += dy * force;

      // ----- damping (air‑like resistance) -----
      const damp = 0.96;                           // 4 % per 1/60 s
      this.vx *= damp;
      this.vy *= damp;

      // ----- move particle -----
      this.x += this.vx * dt;
      this.y += this.vy * dt;

      // ----- wrap‑around edges (optional, gives a “fluid” feel) -----
      const wrap = 20; // margin
      if (this.x < -wrap) this.x = canvas.width  + wrap;
      if (this.x > canvas.width  + wrap) this.x = -wrap;
      if (this.y < -wrap) this.y = canvas.height + wrap;
      if (this.y > canvas.height + wrap) this.y = -wrap;
    }

    // draw with low‑alpha additive blending
    draw() {
      ctx.beginPath();
      ctx.arc(this.x, this.y, 1.2, 0, Math.PI*2);
      const sat = 70 + Math.random()*10;   // a bit of saturation jitter
      const lig = 50 + Math.random()*10;   // lightness jitter
      ctx.fillStyle = `hsla(${this.hue}, ${sat}%, ${lig}%, 0.07)`;
      ctx.fill();
    }
  }

  // ---------------------------------------------------
  // Initialise ~3000 particles spread over the canvas
  // ---------------------------------------------------
  const PARTICLE_COUNT = 3000;
  const particles = [];
  for (let i = 0; i < PARTICLE_COUNT; i++) {
    particles.push(new Particle(
      Math.random() * canvas.width,
      Math.random() * canvas.height
    ));
  }

  // ---------------------------------------------------
  // Interaction state
  // ---------------------------------------------------
  let mouse = { x: canvas.width/2, y: canvas.height/2 }; // default centre
  let mouseMoved = false;
  window.addEventListener('mousemove', e => {
    const rect = canvas.getBoundingClientRect();
    mouse.x = (e.clientX - rect.left) * (canvas.width  / rect.width);
    mouse.y = (e.clientY - rect.top)  * (canvas.height / rect.height);
    mouseMoved = true;
  });
  window.addEventListener('mouseleave', () => {
    mouseMoved = false; // fall back to centre
  });

  // ---------------------------------------------------
  // Animation loop
  // ---------------------------------------------------
  ctx.globalCompositeOperation = 'lighter'; // additive blending
  let lastTime = 0;
  function animate(timestamp) {
    const dt = (timestamp - lastTime) / 1000; // seconds
    lastTime = timestamp;

    // clear only a little (preserve trail) – dark background stays
    ctx.fillStyle = 'rgba(11,11,11,0.95)';
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    const targetX = mouseMoved ? mouse.x : canvas.width / 2;
    const targetY = mouseMoved ? mouse.y : canvas.height / 2;

    for (const p of particles) {
      p.update(targetX, targetY, dt);
      p.draw();
    }

    requestAnimationFrame(animate);
  }
  requestAnimationFrame(animate);

})(); // IIFE – keeps the global namespace clean
</script>
</body>
</html>
```

