<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Generative Ink Drawing – Simplex Noise Agents</title>
<style>
  body,html{margin:0;padding:0;height:100%;overflow:hidden;background:#f8f3eb;}/* warm off‑white */
  canvas{display:block;}
</style>
</head>
<body>
<canvas id="c"></canvas>

<script>
/* ---------- SIMPLEX NOISE (Stefan Gustavson style) ---------- */
// 2‑D simplex noise with a time dimension (3rd arg)
function simplexNoise(x, y, t) {
  const F2 = 0.5 * (Math.sqrt(3) - 1);
  const G2 = (3 - Math.sqrt(3)) / 6;

  // Helper: skew coordinates
  const s = (x + y * F2) * G2;
  const xs = x + s;
  const ys = y + s;
  const i = Math.floor(xs);
  const j = Math.floor(ys);
  const tOffset = Math.cos(t * 0.001) * 0.5 + 0.5; // slowly shift the field

  // Unskew back to get relative coordinates inside the simplex
  const x0 = xs - i;
  const y0 = ys - j;

  // Determine which simplex we are in.
  const i1 = (x0 > y0) ? 1 : 0;
  const j1 = (x0 > y0) ? 0 : 1;

  const x1 = x0 - i1 + G2;
  const y1 = y0 - j1 + G2;
  const x2 = x0 - 1.0 + 2.0 * G2;
  const y2 = y0 - 1.0 + 2.0 * G2;

  // Hash the integer coordinates to a gradient index (0‑7)
  const perm = new Uint8Array(512);
  for (let k = 0; k < 256; k++) perm[k] = Math.floor(Math.random() * 256);
  for (let k = 0; k < 256; k++) perm[256 + k] = perm[k];

  function grad(hash, x, y) {
    const h = hash & 7;
    const u = h < 4 ? x : y;
    const v = h < 4 ? y : x;
    return ((h & 1) === 0 ? u : -u) + ((h & 2) === 0 ? v : -v);
  }

  // Compute contribution of each corner
  let n0, n1, n2;
  const t0 = 0.5 - x0 * x0 - y0 * y0;
  if (t0 < 0) n0 = 0;
  else {
    const vert = 3 * grad(perm[i + perm[j]], x0, y0) * tOffset;
    n0 = t0 * t0 * vert;
  }

  const t1 = 0.5 - x1 * x1 - y1 * y1;
  if (t1 < 0) n1 = 0;
  else {
    const vert = 3 * grad(perm[i + i1 + perm[j + j1]], x1, y1) * tOffset;
    n1 = t1 * t1 * vert;
  }

  const t2 = 0.5 - x2 * x2 - y2 * y2;
  if (t2 < 0) n2 = 0;
  else {
    const vert = 3 * grad(perm[i + 1 + perm[j + 1]], x2, y2) * tOffset;
    n2 = t2 * t2 * vert;
  }

  // Sum contributions and scale to [-1,1]
  return (n0 + n1 + n2) * 1.0; // already in roughly -1..1 range
}

/* ---------- AGENT & RENDERING SETUP ---------- */
const canvas = document.getElementById('c');
const ctx = canvas.getContext('2d');

let width, height, dpr = 1;

function resize() {
  width  = canvas.clientWidth;
  height = canvas.clientHeight;
  dpr    = window.devicePixelRatio || 1;

  // Adjust canvas backing size for DPR
  canvas.width  = width  * dpr;
  canvas.height = height * dpr;
  ctx.scale(dpr, dpr);

  // Clear with warm off‑white
  ctx.fillStyle = '#f8f3eb';
  ctx.fillRect(0, 0, width, height);
}
resize();
window.addEventListener('resize', resize);

/* ---------- AGENT CLASS ---------- */
class Agent {
  constructor() {
    this.x = Math.random() * width;
    this.y = Math.random() * height;
    // Spawn on a random edge if you prefer:
    // this.spawnOnEdge();
    this.vx = 0;
    this.vy = 0;
    this.speed = 1;               // one logical pixel per frame
    this.trail = [];              // stores recent (x,y) points for faint line
  }

  // Move one logical pixel according to the current noise field
  step(time) {
    // Normalise canvas coords to ~[-6,6] for noise (tuning may vary)
    const nx = this.x / (width  / 12);
    const ny = this.y / (height / 12);

    // Get a 2‑D direction vector from noise (we treat noise as an angle)
    const angle = simplexNoise(nx, ny, time) * Math.PI; // -π … +π
    this.vx = Math.cos(angle);
    this.vy = Math.sin(angle);

    // Advance
    this.x += this.vx * this.speed;
    this.y += this.vy * this.speed;

    // Record for trail (keep last ~30 points)
    this.trail.push({x: this.x, y: this.y});
    if (this.trail.length > 30) this.trail.shift();

    // Respawn if we left the canvas
    if (this.x < 0 || this.x > width || this.y < 0 || this.y > height) {
      this.spawnOnEdge();
    }
  }

  spawnOnEdge() {
    // Choose a random side
    const side = Math.floor(Math.random() * 4);
    switch (side) {
      case 0: // left
        this.x = 0; this.y = Math.random() * height; break;
      case 1: // right
        this.x = width;  this.y = Math.random() * height; break;
      case 2: // top
        this.x = Math.random() * width; this.y = 0; break;
      case 3: // bottom
        this.x = Math.random() * width; this.y = height; break;
    }
  }

  // Draw the faint ink trail
  draw() {
    if (this.trail.length < 2) return;

    ctx.strokeStyle = 'rgba(0,0,0,0.07)';   // soft black, low alpha
    ctx.lineWidth = 1;

    ctx.beginPath();
    ctx.moveTo(this.trail[0].x, this.trail[0].y);
    for (let i = 1; i < this.trail.length; i++) {
      const p = this.trail[i];
      ctx.lineTo(p.x, p.y);
    }
    ctx.stroke();
  }
}

/* ---------- WORLD ---------- */
const agents = [];
const agentCount = 200;
for (let i = 0; i < agentCount; i++) {
  agents.push(new Agent());
}

let lastTime = performance.now();

function animate(time) {
  const dt = time - lastTime;
  lastTime = time;

  // Clear previous frame (keep background)
  // ctx.clearRect(0,0,width,height); // not needed because we redraw background each resize

  // Update & draw each agent
  for (const a of agents) {
    a.step(time);
    a.draw();
  }

  requestAnimationFrame(animate);
}
requestAnimationFrame(animate);

</script>
</body>
</html>
```

### How it works

1. **Simplex noise** – a compact 2‑D implementation (no external libraries).  
   The third argument `t` (time) is used to slowly shift the gradient hash, giving the field a gentle evolution.

2. **Agents** – each stores its position, a short trail (`Array` of the last ~30 points), and computes a direction from the noise field (`angle = noise * π`).  
   Moving one logical pixel per frame (`speed = 1`) keeps the drawing smooth.

3. **Resurrection** – when an agent steps outside the canvas it calls `spawnOnEdge()`, picking a random side to re‑enter.

4. **Rendering** – the canvas background is set to a warm off‑white (`#f8f3eb`).  
   The ink lines use a very low‑alpha black (`rgba(0,0,0,0.07)`) so strokes accumulate softly, producing the “generative ink drawing” feel after a few seconds.

5. **Resize & DPR** – the `resize` function adjusts the backing buffer to the device pixel ratio, preserving sharpness on high‑DPI screens, and re‑applies the warm background.

