*(Copy the whole block into a file and open it in a browser that supports WebGL 2. All code – HTML, CSS and JavaScript – lives inside this one file.)*

```html
<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>WebGL 2 Ray‑marched Morphing Scene</title>
<style>
  body,html{margin:0;padding:0;overflow:hidden;height:100%;width:100%;}
  canvas{display:block;width:100%;height:100%;}
  #log{position:absolute;top:0;left:0;right:0;bottom:0;pointer-events:none;
        font-family:monospace;background:rgba(0,0,0,0.7);
        color:#0f0;padding:1rem;z-index:10;overflow:auto;}
</style>
</head>
<body>
<pre id="log"></pre>
<canvas id="glcanvas"></canvas>

<script>
(() => {
  // ------------------------------------------------------------
  // 1.  BASIC WEBGL SETUP
  // ------------------------------------------------------------
  const canvas = document.getElementById('glcanvas');
  const dpr    = window.devicePixelRatio || 1;
  canvas.width  = canvas.clientWidth  * dpr;
  canvas.height = canvas.clientHeight * dpr;

  const gl = canvas.getContext('webgl2');
  if (!gl) throw new Error('WebGL 2 not available');

  // -----------------------------------------------------------------
  // 2.  SHADER SOURCES (inline string literals)
  // -----------------------------------------------------------------
  const vertexShaderSrc = `#version 300 es
  layout(location = 0) in vec3 aPosition;
  layout(location = 1) in vec2 aTexCoord;

  out vec2 vUv;

  void main() {
    vUv = aTexCoord;
    gl_Position = vec4(aPosition, 1.0);
  }`;

  const fragmentShaderSrc = `#version 300 es
  precision highp float;

  in vec2 vUv;
  out vec4 fragColor;

  uniform float iTime;
  uniform mat4 viewMatrix;
  uniform mat4 projMatrix;
  uniform vec3 lightDir;   // world‑space directional light

  // ---------- helper distance functions ----------
  float sdSphere(vec3 p, float r) {
    return length(p) - r;
  }

  float sdTorus(vec3 p, vec2 t) {
    vec2 q = vec2(length(p.xz) - t.x, p.y);
    return length(q) - t.y;
  }

  // smooth‑min (k = 0.1 works nicely)
  float smin(float a, float b, float k) {
    float h = clamp(0.5 + 0.5*(b - a)/k, 0.0, 1.0);
    return mix(b, a, h) - k*h*(1.0 - h);
  }

  // ground plane with a subtle checker
  float sdGround(vec3 p) {
    // plane at y = -1
    float plane = p.y + 1.0;
    // checker pattern in the XY plane (scale 4)
    float check = (mod(floor(p.x*0.25),2.0) == mod(floor(p.z*0.25),2.0)) ? 0.0 : 1.0;
    // blend a tiny height variation based on the checker
    return plane + 0.05 * check;
  }

  // signed distance of the whole scene (union via smooth‑min)
  float sceneSDF(vec3 p) {
    // moving sphere
    float r = 0.6 + 0.2 * sin(iTime * 0.7);
    float dSphere = sdSphere(p, r);

    // torus that morphs its tube radius
    vec2 torusParams = vec2(1.0, 0.25 + 0.15 * sin(iTime * 1.1));
    float dTorus = sdTorus(p, torusParams);

    // ground plane
    float dGround = sdGround(p);

    // smooth‑min union of the two 3D objects, then min with ground (ground is “floor”)
    float unionObj = smin(dSphere, dTorus, 0.12);
    return min(unionObj, dGround);
  }

  // ---------- simple ray‑march ----------
  const int MAX_STEPS = 64;
  const float EPS = 0.0005;
  const float FAR = 100.0;

  vec3 rayMarch(vec3 ro, vec3 rd) {
    float depth = 0.0;
    for (int i = 0; i < MAX_STEPS; i++) {
      vec3 p = ro + depth * rd;
      float d = sceneSDF(p);
      if (d < EPS || depth > FAR) break;
      depth += d;
    }
    return (depth > FAR) ? vec3(0.0) : (ro + depth * rd);
  }

  // Lambert + simple Phong specular (hard‑coded shininess)
  vec3 lighting(vec3 hitPos) {
    vec3 N = normalize( gradientSDF(hitPos) );
    vec3 L = normalize( -lightDir );
    float lambert = max(dot(N, L), 0.0);

    // simple Phong spec (shininess = 20)
    vec3 V = normalize( vec3(0.0, 2.0, -5.0) - hitPos ); // eye from a fixed point
    vec3 R = reflect(-L, N);
    float spec = pow(max(dot(R, V), 0.0), 20.0);

    vec3 baseColor = vec3(0.9, 0.6, 0.3); // warm stone
    return baseColor * lambert + vec3(1.0) * spec;
  }

  // analytic gradient approximation (central differences)
  vec3 gradientSDF(vec3 p) {
    float eps = 0.0005;
    return vec3(
      sceneSDF(p + vec3(eps,0.0,0.0)) - sceneSDF(p - vec3(eps,0.0,0.0)),
      sceneSDF(p + vec3(0.0,eps,0.0)) - sceneSDF(p - vec3(0.0,eps,0.0)),
      sceneSDF(p + vec3(0.0,0.0,eps)) - sceneSDF(p - vec3(0.0,0.0,eps))
    );
  }

  // ---------- main ----------
  void main() {
    // map fragment coord (0‑1) to screen space (-1‑1)
    vec2 uv = vUv * 2.0 - vec2(1.0);
    // simple perspective camera
    float fov = radians(60.0);
    vec3 camPos = vec3(0.0, 1.5, -4.0);
    vec3 lookAt = vec3(0.0, 0.0, 0.0);
    vec3 camDir = normalize(lookAt - camPos);
    vec3 camRight = normalize(cross(camDir, vec3(0.0,1.0,0.0)));
    vec3 camUp    = normalize(cross(camRight, camDir));

    // build ray direction (NDC → world)
    vec3 dirX = camRight * cos(fov * uv.x);
    vec3 dirY = camUp    * sin(fov * uv.y);
    vec3 rayDir = normalize(dirX + dirY + camDir);

    // ray‑march
    vec3 hit = rayMarch(camPos, rayDir);
    bvec3 hitMask = greaterThanEqual(hit, vec3(0.0));

    if (any(hitMask)) {
      vec3 col = lighting(hit);
      fragColor = vec4(col, 1.0);
    } else {
      // background gradient (dawn)
      vec2 t = vUv;
      vec3 bg = mix(vec3(0.1,0.0,0.2), vec3(0.6,0.5,0.7), t.y);
      fragColor = vec4(bg, 1.0);
    }
  }
  `;

  // -----------------------------------------------------------------
  // 3.  COMPILATION HELPERS (with error logging)
  // -----------------------------------------------------------------
  function compileShader(src, type) {
    const shader = gl.createShader(type);
    gl.shaderSource(shader, src);
    gl.compileShader(shader);
    if (!gl.getShaderParameter(shader, gl.COMPILE_STATUS)) {
      const log = gl.getShaderInfoLog(shader);
      console.error(`Shader compile error: ${log}`);
      document.getElementById('log').textContent += `Shader compile error:\n${log}\n`;
      gl.deleteShader(shader);
      return null;
    }
    return shader;
  }

  // -----------------------------------------------------------------
  // 4.  CREATE PROGRAM
  // -----------------------------------------------------------------
  const vertexShader = compileShader(vertexShaderSrc, gl.VERTEX_SHADER);
  if (!vertexShader) throw new Error('Vertex shader failed');
  const fragmentShader = compileShader(fragmentShaderSrc, gl.FRAGMENT_SHADER);
  if (!fragmentShader) throw new Error('Fragment shader failed');

  const program = gl.createProgram();
  gl.attachShader(program, vertexShader);
  gl.attachShader(program, fragmentShader);
  gl.linkProgram(program);
  if (!gl.getProgramParameter(program, gl.LINK_STATUS)) {
    const log = gl.getProgramInfoLog(program);
    console.error(`Program link error: ${log}`);
    document.getElementById('log').textContent += `Program link error:\n${log}\n`;
    gl.deleteProgram(program);
    return;
  }
  gl.deleteShader(vertexShader);
  gl.deleteShader(fragmentShader);

  // -----------------------------------------------------------------
  // 5.  BUFFER SETUP (fullscreen quad)
  // -----------------------------------------------------------------
  const positionBuffer = gl.createBuffer();
  gl.bindBuffer(gl.ARRAY_BUFFER, positionBuffer);
  const positions = new Float32Array([
    -1, -1, 0,   // 0
     3, -1, 0,   // 1
    -1,  3, 0,   // 2
    -1,  3, 0,   // 3 (repeat vertex 2)
     3, -1, 0,   // 4 (repeat vertex 1)
     3,  3, 0    // 5
  ]);
  gl.bufferData(gl.ARRAY_BUFFER, positions, gl.STATIC_DRAW);

  const texCoordBuffer = gl.createBuffer();
  gl.bindBuffer(gl.ARRAY_BUFFER, texCoordBuffer);
  const texCoords = new Float32Array([
    0.0, 0.0,   // 0
    2.0, 0.0,   // 1
    0.0, 2.0,   // 2
    0.0, 2.0,   // 3 (repeat)
    2.0, 0.0,   // 4 (repeat)
    2.0, 2.0    // 5
  ]);
  gl.bufferData(gl.ARRAY_BUFFER, texCoords, gl.STATIC_DRAW);

  // attribute locations (as declared in shaders)
  const aPositionLoc = 0;
  const aTexCoordLoc = 1;

  // -----------------------------------------------------------------
  // 6.  UNIFORM LOCATIONS
  // -----------------------------------------------------------------
  const u_iTime   = gl.getUniformLocation(program, 'iTime');
  const u_view    = gl.getUniformLocation(program, 'viewMatrix');
  const u_proj    = gl.getUniformLocation(program, 'projMatrix');
  const u_lightDir = gl.getUniformLocation(program, 'lightDir');

  if (!u_iTime || !u_view || !u_proj || !u_lightDir) {
    console.error('Failed to locate required uniforms');
    document.getElementById('log').textContent += 'Uniform location error\n';
    return;
  }

  // -----------------------------------------------------------------
  // 7.  MATRIX UTILITIES (tiny hand‑rolled)
  // -----------------------------------------------------------------
  const mat4 = {
    perspective(out, fovy, aspect, near, far) {
      const f = 1.0 / Math.tan(fovy / 2);
      out[0]  = f / aspect; out[1] = 0;          out[2] = 0;                 out[3] = 0;
      out[4]  = 0;          out[5] = f;          out[6] = 0;                 out[7] = 0;
      out[8]  = 0;          out[9] = 0;          out[10] = (far+near)/(near-far); out[11]= -1;
      out[12] = 0;          out[13]= 0;          out[14]= (2*far*near)/(near-far); out[15]= 0;
    },
    lookAt(out, eye, center, up) {
      const z = [center[0]-eye[0], center[1]-eye[1], center[2]-eye[2]];
      const len = Math.sqrt(z[0]*z[0]+z[1]*z[1]+z[2]*z[2]);
      z[0]/=len; z[1]/=len; z[2]/=len;
      const x = [];
      const y = [];
      vec3.cross(x, up, z);
      vec3.normalize(x, x);
      vec3.cross(y, z, x);
      out.set([
        x[0], y[0], z[0], 0,
        x[1], y[1], z[1], 0,
        x[2], y[2], z[2], 0,
        -vec3.dot(x, eye), -vec3.dot(y, eye), -vec3.dot(z, eye), 1
      ]);
    }
  };

  const vec3 = {
    cross(out, a, b) {
      out[0] = a[1]*b[2] - a[2]*b[1];
      out[1] = a[2]*b[0] - a[0]*b[2];
      out[2] = a[0]*b[1] - a[1]*b[0];
    },
    normalize(out, v) {
      const len = Math.sqrt(v[0]*v[0] + v[1]*v[1] + v[2]*v[2]);
      out[0] = v[0]/len; out[1] = v[1]/len; out[2] = v[2]/len;
    },
    dot(a, b) { return a[0]*b[0] + a[1]*b[1] + a[2]*b[2]; }
  };

  // -----------------------------------------------------------------
  // 8.  RESIZE HANDLING (keeps fullscreen and respects DPR)
  // -----------------------------------------------------------------
  function onResize() {
    const width  = canvas.clientWidth  * dpr;
    const height = canvas.clientHeight * dpr;
    if (canvas.width !== width || canvas.height !== height) {
      canvas.width  = width;
      canvas.height = height;
      gl.viewport(0, 0, width, height);

      // update projection matrix
      const proj = new Float32Array(16);
      mat4.perspective(proj, Math.radians(60), width/height, 0.1, 100);
      gl.uniformMatrix4fv(u_proj, false, proj);
    }
  }
  window.addEventListener('resize', onResize);
  onResize(); // initial

  // -----------------------------------------------------------------
  // 9.  RENDER LOOP
  // -----------------------------------------------------------------
  const start = performance.now();
  function animate() {
    const t = (performance.now() - start) * 0.001; // seconds
    gl.useProgram(program);

    // ---- attributes ----
    gl.bindBuffer(gl.ARRAY_BUFFER, positionBuffer);
    gl.vertexAttribPointer(aPositionLoc, 3, gl.FLOAT, false, 0, 0);
    gl.enableVertexAttribArray(aPositionLoc);

    gl.bindBuffer(gl.ARRAY_BUFFER, texCoordBuffer);
    gl.vertexAttribPointer(aTexCoordLoc, 2, gl.FLOAT, false, 0, 0);
    gl.enableVertexAttribArray(aTexCoordLoc);

    // ---- matrices (view = simple look‑at, static) ----
    const view = new Float32Array(16);
    mat4.lookAt(view, [0, 1.5, -4], [0,0,0], [0,1,0]);
    gl.uniformMatrix4fv(u_view, false, view);

    // ---- time & moving light ----
    gl.uniform1f(u_iTime, t);

    // light rotates around the origin
    const lightAngle = t * 0.4;
    const lx = Math.cos(lightAngle);
    const ly = 0.7 + 0.3 * Math.sin(lightAngle * 0.5); // keep it above horizon
    const lz = Math.sin(lightAngle);
    const lightDirNorm = Math.sqrt(lx*lx + ly*ly + lz*lz);
    gl.uniform3fv(u_lightDir, [lx/lightDirNorm, ly/lightDirNorm, lz/lightDirNorm]);

    // ---- draw ----
    gl.drawArrays(gl.TRIANGLES, 0, 6);

    requestAnimationFrame(animate);
  }
  requestAnimationFrame(animate);
})();

// Helper – because Math has no radians()
Math.radians = function(deg) { return deg * Math.PI / 180; };
</script>
</body>
</html>
```

### What the page does

1. **Full‑screen `<canvas>`** that automatically resizes with the window and respects the device pixel ratio.  
2. **Vertex shader** simply passes a fullscreen quad’s position & texture coordinates to the fragment shader.  
3. **Fragment shader** (inline string literal) implements a **ray‑marched signed‑distance field**:
   * A **smooth‑min union** of a **morphing sphere** (radius varies with `sin(iTime)`) and a **torus** (tube radius also animated).  
   * A **ground plane** with a subtle checker pattern.  
   * **Lambert + Phong specular** lighting using one **moving directional light** whose direction circles the origin.  
4. **Error handling** – any shader compile or program link failure writes the info log both to the console **and** into the on‑page `<pre id="log">` element, so you’ll see it even if the canvas stays black.  
5. **No external libraries** – pure WebGL 2 API, tiny hand‑rolled matrix helpers, and only the HTML/CSS needed for layout.  

Open the file in a modern browser (Chrome, Edge, Firefox, Safari) and you should see a smoothly animating, 3‑D‑looking scene that fills the entire viewport.

