Copy the whole block into a file (e.g. `cloth.html`) and open it in any modern browser.

```html
<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Cloth Simulation (Verlet)</title>
<style>
  body,html{margin:0;padding:0;overflow:hidden;background:#111;}
  canvas{display:block;}
</style>
</head>
<body>
<canvas id="c"></canvas>

<script>
(() => {
  'use strict';

  const canvas = document.getElementById('c');
  const ctx = canvas.getContext('2d');

  // --------------------------------------------------
  // Configuration
  // --------------------------------------------------
  const ROWS = 16, COLS = 24;          // grid size
  const SIZE = { w: 800, h: 600 };    // desired logical size (will be scaled by DPR)
  const GRAVITY = { x: 0, y: 300 };   // pixels / s² (downwards)
  const TIME_STEP = 1/60;             // seconds
  const DAMPING = 0.96;               // velocity damping (energy loss)
  const SOLVER_ITERS = 6;             // number of constraint relaxations per frame
  const DRAG_RADIUS = 30;             // px – area that feels mouse drag
  const CUT_RADIUS = 20;              // px – area that can cut a constraint

  // --------------------------------------------------
  // Helpers
  // --------------------------------------------------
  const lerp = (a, b, t) => a + (b - a) * t;
  const distSq = (a, b) => (a.x - b.x) ** 2 + (a.y - b.y) ** 2;
  const sub = (a, b) => ({ x: a.x - b.x, y: a.y - b.y });
  const add = (a, b) => ({ x: a.x + b.x, y: a.y + b.y });
  const scale = (v, s) => ({ x: v.x * s, y: v.y * s });
  const length = v => Math.sqrt(v.x ** 2 + v.y ** 2);

  // --------------------------------------------------
  // Point & Constraint definitions
  // --------------------------------------------------
  class Point {
    constructor(x, y) {
      this.pos = { x, y };      // current position
      this.prev = { x, y };     // previous position (Verlet store)
      this.anchor = null;       // if pinned, stores the fixed point
      this.mass = 1;            // uniform mass (doesn't affect constraint solver)
      this.fixed = false;       // whether this point is currently pinned
    }
  }

  class Constraint {
    constructor(p0, p1) {
      this.p0 = p0;
      this.p1 = p1;
      this.restLength = length(sub(p0.pos, p1.pos));
    }
    // satisfy this constraint (Proj. Gauss‑Seidel style)
    satisfy() {
      const dx = this.p1.pos.x - this.p0.pos.x;
      const dy = this.p1.pos.y - this.p0.pos.y;
      const current = Math.hypot(dx, dy);
      if (current === 0) return;               // avoid division by zero
      const diff = (this.restLength - current) / current;
      const off0 = scale({ x: dx, y: dy }, diff * 0.5);
      const off1 = scale({ x: -dx, y: -dy }, diff * 0.5);
      // only move non‑pinned points
      if (!this.p0.fixed) this.p0.pos.x -= off0.x; this.p0.pos.y -= off0.y;
      if (!this.p1.fixed) this.p1.pos.x += off1.x; this.p1.pos.y += off1.y;
    }
  }

  // --------------------------------------------------
  // Build grid
  // --------------------------------------------------
  const points = [];
  const constraints = []; // flat array; we will later filter out cut ones

  for (let r = 0; r <= ROWS; r++) {
    for (let c = 0; c <= COLS; c++) {
      const x = (c / COLS) * SIZE.w;
      const y = (r / ROWS) * SIZE.h;
      const p = new Point(x, y);
      points.push(p);
    }
  }

  // --------------------------------------------------
  // Create horizontal & vertical constraints
  // --------------------------------------------------
  for (let r = 0; r < ROWS; r++) {
    for (let c = 0; c < COLS; c++) {
      const i = r * (COLS + 1) + c;
      // horizontal (right)
      constraints.push(new Constraint(points[i], points[i + 1]));
      // vertical (down)
      constraints.push(new Constraint(points[i], points[i + (COLS + 1)]));
    }
  }

  // --------------------------------------------------
  // Pin the top row (they stay where they are)
  // --------------------------------------------------
  for (let c = 0; c <= COLS; c++) {
    const p = points[c];
    p.anchor = { x: p.pos.x, y: p.pos.y };
    p.fixed = true;
  }

  // --------------------------------------------------
  // Interaction state
  // --------------------------------------------------
  let dragging = false;
  let dragIndex = -1;
  let dragOffset = { x: 0, y: 0 };

  // --------------------------------------------------
  // Resize handling + DPR
  // --------------------------------------------------
  function resize() {
    const dpr = window.devicePixelRatio || 1;
    const w = Math.floor(canvas.clientWidth * dpr);
    const h = Math.floor(canvas.clientHeight * dpr);
    canvas.width = w;
    canvas.height = h;
    const scale = Math.min(w / SIZE.w, h / SIZE.h);
    ctx.scale(scale, scale);   // now 1 unit = 1 logical pixel
  }
  window.addEventListener('resize', resize);
  resize(); // initial

  // --------------------------------------------------
  // Mouse handling
  // --------------------------------------------------
  let btn = -1; // -1 = none, 0 = left, 1 = right (or shift+left)

  canvas.addEventListener('mousedown', ev => {
    if (ev.button === 0) btn = 0;          // left drag
    if (ev.button === 2 || (ev.button === 0 && ev.shiftKey)) btn = 1; // right / shift+left (cut)
    const rect = canvas.getBoundingClientRect();
    const mx = (ev.clientX - rect.left) / canvas.clientWidth * SIZE.w;
    const my = (ev.clientY - rect.top) / canvas.clientHeight * SIZE.h;

    // find nearest point
    let nearest = null;
    let nearestDist = Infinity;
    points.forEach(p => {
      const d = distSq(p.pos, { x: mx, y: my });
      if (d < nearestDist) { nearestDist = d; nearest = p; }
    });

    if (btn === 0) {
      dragging = true;
      dragIndex = points.indexOf(nearest);
      dragOffset.x = nearest.pos.x - mx;
      dragOffset.y = nearest.pos.y - my;
      nearest.pos.x = mx;
      nearest.pos.y = my;
      nearest.prev = { x: mx, y: my }; // reset previous to avoid sudden jump
    } else if (btn === 1 && nearestDist < CUT_RADIUS * CUT_RADIUS) {
      // find a constraint that involves this point and remove it
      const idx = constraints.findIndex(c => c.p0 === nearest || c.p1 === nearest);
      if (idx !== -1) constraints.splice(idx, 1);
    }
  });

  canvas.addEventListener('mousemove', ev => {
    if (!dragging) return;
    const rect = canvas.getBoundingClientRect();
    const mx = (ev.clientX - rect.left) / canvas.clientWidth * SIZE.w;
    const my = (ev.clientY - rect.top) / canvas.clientHeight * SIZE.h;
    const p = points[dragIndex];
    p.pos.x = mx + dragOffset.x;
    p.pos.y = my + dragOffset.y;
    p.prev = { x: p.pos.x, y: p.pos.y }; // keep prev in sync while dragging
  });

  canvas.addEventListener('mouseup', () => {
    if (dragging) {
      dragging = false;
      dragIndex = -1;
    }
    btn = -1; // release button
  });

  // Prevent context menu on right‑click (only when we are in cut mode)
  canvas.addEventListener('contextmenu', ev => ev.preventDefault());

  // --------------------------------------------------
  // Main loop
  // --------------------------------------------------
  function update() {
    // 1. Apply gravity to every non‑pinned point
    points.forEach(p => {
      if (p.fixed) return;
      // Verlet step: pos = 2*pos - prev + accel*dt²
      const g = GRAVITY;
      p.pos.y += g.y * TIME_STEP * TIME_STEP;
    });

    // 2. Verlet integration (simple: pos = 2*pos - prev)
    points.forEach(p => {
      if (p.fixed) {
        // pinned points keep their anchored position
        p.pos.x = p.anchor.x;
        p.pos.y = p.anchor.y;
      } else {
        const next = {
          x: 2 * p.pos.x - p.prev.x + GRAVITY.x * TIME_STEP * TIME_STEP,
          y: 2 * p.pos.y - p.prev.y + GRAVITY.y * TIME_STEP * TIME_STEP,
        };
        // store current pos into prev for next frame
        p.prev = p.pos;
        p.pos = next;
        // damping (simple velocity filter)
        p.pos.x *= DAMPING;
        p.pos.y *= DAMPING;
      }
    });

    // 3. Constraint satisfaction (multiple iterations)
    for (let i = 0; i < SOLVER_ITERS; i++) {
      constraints.forEach(c => c.satisfy());
    }

    // 4. Rendering
    render();
    requestAnimationFrame(update);
  }

  // --------------------------------------------------
  // Rendering: thin lines + subtle per‑quad gradient
  // --------------------------------------------------
  function render() {
    const w = SIZE.w;
    const h = SIZE.h;
    ctx.clearRect(0, 0, canvas.width, canvas.height);

    // draw edges (horizontal + vertical)
    ctx.strokeStyle = '#777';
    ctx.lineWidth = 1;
    for (let r = 0; r <= ROWS; r++) {
      for (let c = 0; c <= COLS; c++) {
        const i = r * (COLS + 1) + c;
        // horizontal edge (if exists)
        if (c < COLS) {
          const p0 = points[i];
          const p1 = points[i + 1];
          ctx.beginPath();
          ctx.moveTo(p0.pos.x, p0.pos.y);
          ctx.lineTo(p1.pos.x, p1.pos.y);
          ctx.stroke();
        }
        // vertical edge (if exists)
        if (r < ROWS) {
          const p0 = points[i];
          const p1 = points[i + (COLS + 1)];
          ctx.beginPath();
          ctx.moveTo(p0.pos.x, p0.pos.y);
          ctx.lineTo(p1.pos.x, p1.pos.y);
          ctx.stroke();
        }
      }
    }

    // draw filled quads with a subtle gradient per quad
    ctx.fillStyle = '#000';
    for (let r = 0; r < ROWS; r++) {
      for (let c = 0; c < COLS; c++) {
        const a = points[r * (COLS + 1) + c];          // top‑left
        const b = points[r * (COLS + 1) + (c + 1)];   // top‑right
        const d = points[(r + 1) * (COLS + 1) + c];   // bottom‑left
        const e = points[(r + 1) * (COLS + 1) + (c + 1)]; // bottom‑right

        // simple average colour based on vertical position (darker at bottom)
        const t = (a.pos.y + d.pos.y) / (2 * h); // 0..1
        const col = `rgba(48,48,48,${0.15 * (1 - t)})`;

        ctx.beginPath();
        ctx.moveTo(a.pos.x, a.pos.y);
        ctx.lineTo(b.pos.x, b.pos.y);
        ctx.lineTo(e.pos.x, e.pos.y);
        ctx.lineTo(d.pos.x, d.pos.y);
        ctx.closePath();

        ctx.fillStyle = col;
        ctx.fill();
      }
    }
  }

  // --------------------------------------------------
  // Start the animation
  // --------------------------------------------------
  update();
})();
</script>
</body>
</html>
