<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Radial Audio Visualizer</title>
<style>
  body,html{margin:0;padding:0;height:100%;overflow:hidden;background:#000}
  #overlay{
    position:absolute;top:0;left:0;right:0;bottom:0;
    display:flex;align-items:center;justify-content:center;
    font-family:sans-serif;font-size:2rem;color:#fff;
    opacity:0.9;pointer-events:none;
  }
  canvas{display:block;}
</style>
</head>
<body>
<div id="overlay">Click to start</div>
<canvas id="c"></canvas>

<script>
(() => {
  const canvas = document.getElementById('c');
  const ctx = canvas.getContext('2d');
  const overlay = document.getElementById('overlay');

  let audioCtx = null;
  let analyser = null;
  let source = null;
  let animationId = 0;
  let overlayFade = 1;               // 1 = visible, 0 = hidden

  // ---------- Helpers ----------
  function resizeCanvas() {
    const dpr = window.devicePixelRatio || 1;
    const w = window.innerWidth * dpr;
    const h = window.innerHeight * dpr;
    const size = Math.min(w, h) * 0.9;
    canvas.width = size * dpr;
    canvas.height = size * dpr;
    canvas.style.width = `${size}px`;
    canvas.style.height = `${size}px`;
    ctx.scale(dpr, dpr);
  }

  function startAnimation() {
    if (!audioCtx) return;
    animationId = requestAnimationFrame(render);
  }

  function stopAnimation() {
    if (animationId) cancelAnimationFrame(animationId);
  }

  function fadeOverlay() {
    if (overlayFade <= 0) {
      overlay.style.display = 'none';
      return;
    }
    overlayFade = Math.max(0, overlayFade - 0.03);
    overlay.style.opacity = overlayFade;
    requestAnimationFrame(fadeOverlay);
  }

  // ---------- Rendering ----------
  const BAR_COUNT = 64;               // radial bars
  const FFT_SIZE = 1024;              // analyser FFT size
  const MAX_AMPLITUDE = 255;          // 8‑bit per channel

  function render() {
    animationId = requestAnimationFrame(render);

    // get frequency data
    const freqArray = new Uint8Array(analyser.frequencyBinCount);
    analyser.getByteFrequencyData(freqArray);

    // clear & translate to centre
    ctx.clearRect(0, 0, canvas.width, canvas.height);
    const cx = canvas.width / 2;
    const cy = canvas.height / 2;
    const radius = canvas.height / 2 * 0.9; // 90 % of height

    // smooth bass‑pump: average of the lowest bins (0‑16)
    const bassBins = 16;
    let bassAvg = 0;
    for (let i = 0; i < bassBins; i++) {
      bassAvg += freqArray[i];
    }
    bassAvg /= bassBins;
    const bassScale = 0.5 + 0.5 * Math.sin(performance.now() * 0.004) * (bassAvg / 255); // 0.5‑1.0 range

    // draw each bar
    for (let i = 0; i < BAR_COUNT; i++) {
      // map bar index → analyser bins (simple linear split)
      const binStart = Math.floor((i * analyser.frequencyBinCount) / BAR_COUNT);
      const binEnd   = Math.floor(((i + 1) * analyser.frequencyBinCount) / BAR_COUNT);
      let amp = 0;
      for (let j = binStart; j < binEnd; j++) {
        amp += freqArray[j];
      }
      amp = amp / (binEnd - binStart);               // average for this sector
      const height = (amp / MAX_AMPLITUDE) * radius * bassScale; // scaled length

      // hue based on frequency position (low → red, high → violet)
      const hue = ((i / BAR_COUNT) * 240) + 0; // 0‑240° hue

      ctx.beginPath();
      const angle = Math.PI * 2 * (i / BAR_COUNT) - Math.PI / 2; // start at top
      ctx.moveTo(cx, cy);
      ctx.lineTo(cx + Math.cos(angle) * radius,
                 cy + Math.sin(angle) * radius);
      ctx.lineTo(cx + Math.cos(angle) * (radius + height),
                 cy + Math.sin(angle) * (radius + height));
      ctx.lineTo(cx, cy);
      ctx.closePath();

      ctx.fillStyle = `hsl(${hue},70%,50%)`;
      ctx.fill();
    }
  }

  // ---------- Audio setup ----------
  function initAudio() {
    // 1️⃣ Create / resume AudioContext inside a user gesture
    try {
      audioCtx = new (window.AudioContext || window.webkitAudioContext)();
      // If the context is not in 'running' state (e.g., first use), resume it
      if (audioCtx.state === 'suspended') {
        audioCtx.resume();
      }
    } catch (e) {
      console.error('AudioContext error:', e);
      // If we cannot create a context at all, just return – visualizer won't run
      return;
    }

    analyser = audioCtx.createAnalyser();
    analyser.fftSize = FFT_SIZE;
    analyser.minDecibels = -90;
    analyser.maxDecibels = -30;

    // ---------- MediaStream (mic) ----------
    if (navigator.mediaDevices) {
      navigator.mediaDevices.getUserMedia({ audio: true })
        .then(stream => {
          source = audioCtx.createMediaStreamSource(stream);
          source.connect(analyser);
        })
        .catch(err => {
          // Mic permission denied → fallback to synthetic source
          console.warn('Mic denied, using synthetic fallback', err);
          const osc = audioCtx.createOscillator();
          const noise = audioCtx.createBufferSource();
          osc.frequency.value = 1;                // 1 Hz sine (visible pulse)
          osc.type = 'sine';
          osc.connect(analyser);
          osc.start();

          // band‑limited white noise, slowly varying frequency
          noise.buffer = audioCtx.createBuffer(1, audioCtx.sampleRate, audioCtx.sampleRate);
          const noiseData = noise.buffer.getChannelData(0);
          for (let i = 0; i < noiseData.length; i++) {
            noiseData[i] = Math.random() * 2 - 1; // -1 … 1
          }
          noise.loop = true;
          noise.buffer = noise.buffer;
          noise.connect(analyser);
          noise.start(0);
          // Drift frequency a little to add motion
          setInterval(() => {
            if (osc) osc.frequency.setTargetAtTime(1 + Math.random() * 0.5, audioCtx.currentTime, 0.01);
          }, 500);
        });
    } else {
      // Older browsers → synthetic only
      const osc = audioCtx.createOscillator();
      osc.frequency.value = 1;
      osc.type = 'sine';
      osc.connect(analyser);
      osc.start();
    }

    // Connect analyser to destination (required for iOS etc.)
    analyser.connect(audioCtx.destination);
  }

  // ---------- Event wiring ----------
  function onClick() {
    // Only create/resume AudioContext on user gesture
    initAudio();
    overlayFade = 0;                // hide overlay
    fadeOverlay();
    startAnimation();
  }

  window.addEventListener('resize', resizeCanvas);
  canvas.addEventListener('click', onClick);
  document.body.addEventListener('click', onClick); // any click on page

  // Initial canvas size
  resizeCanvas();

  // If the page loads with immediate permission grant (some browsers auto‑grant),
  // we still wait for a click before starting – per spec requirement.
})();
</script>
</body>
</html>
